/* Test driver */
public class Main {
    public static void main(String[] args) throws Exception {
        CircuitBreakerConfig cfg = new CircuitBreakerConfig(3, 5000, 2);
        CircuitBreaker cb = new CircuitBreaker("S", cfg);
        ServiceCall<String> bad = () -> { throw new RuntimeException("boom"); };
        for (int i = 0; i < 3; i++) { try { cb.execute(bad); } catch (Exception ignore) {} }
        System.out.println("FINAL_STATE=" + cb.getStateName());
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) throws Exception {
        CircuitBreakerConfig cfg = new CircuitBreakerConfig(2, 60000, 2);
        CircuitBreaker cb = new CircuitBreaker("S", cfg);
        ServiceCall<String> bad = () -> { throw new RuntimeException("boom"); };
        for (int i = 0; i < 2; i++) { try { cb.execute(bad); } catch (Exception ignore) {} }
        final int[] invoked = {0};
        ServiceCall<String> good = () -> { invoked[0]++; return "OK"; };
        try { cb.execute(good); System.out.println("WRONG"); } catch (RuntimeException e) { System.out.println("REJECTED:" + e.getMessage() + " invoked=" + invoked[0]); }
    }
}
